sql:
INSERT INTO RF_Tabla_Desarrollo_Interna ( Fec_Pro, Cod_Emp, Moneda, Cod_A_P, Cod_Pro, Cod_Sub_Pro, Fec_Pago, Dias_Pago, Cap_Amort, Int_Total_Cont, VP_Cap_Amort, VP_Int_Total_Cont, Precio_Mid, Flujo_CLP )
SELECT RF_PLI_044f_CarteraInv_FFMM.Fec_Pro, RF_PLI_044f_CarteraInv_FFMM.Cod_Emp, RF_PLI_044f_CarteraInv_FFMM.Moneda, RF_PLI_044f_CarteraInv_FFMM.Cod_A_P, RF_PLI_044f_CarteraInv_FFMM.Cod_Pro, RF_PLI_044f_CarteraInv_FFMM.Cod_Sub_Pro, RF_PLI_044f_CarteraInv_FFMM.Fec_Vcto_Cup AS Fec_Pago, RF_PLI_044f_CarteraInv_FFMM.Dias_Liq AS Dias_Pago, RF_PLI_044f_CarteraInv_FFMM.Cap_Amort, RF_PLI_044f_CarteraInv_FFMM.Int_Total_Cont, RF_PLI_044f_CarteraInv_FFMM.VP_Cap_Amort, RF_PLI_044f_CarteraInv_FFMM.VP_Int_Total AS VP_Int_Total_Cont, Precios_Dia.Precio_Mid, ([RF_PLI_044f_CarteraInv_FFMM].[VP_Cap_Amort]+[RF_PLI_044f_CarteraInv_FFMM].[VP_Int_Total])*[Precios_Dia].[Precio_Mid] AS Flujo_CLP
FROM Precios_Dia INNER JOIN RF_PLI_044f_CarteraInv_FFMM ON Precios_Dia.NEMOTECNICO = RF_PLI_044f_CarteraInv_FFMM.Moneda;

SELECT RF_base_Completa_Hist.Fec_Pro, RF_base_Completa_Hist.Cod_Emp, RF_base_Completa_Hist.Moneda, RF_base_Completa_Hist.Cod_A_P, "ML_C46_Inversiones_Financieras" AS Cod_Pro, "ML_C46_Inversiones_Financieras_FFMM" AS Cod_Sub_Pro, RF_base_Completa_Hist.Num_Oper, RF_base_Completa_Hist.Num_Cup, RF_base_Completa_Hist.Emisor, RF_base_Completa_Hist.Nemotecnico, RF_base_Completa_Hist.Tasa_Emi, RF_base_Completa_Hist.Compensacion, RF_base_Completa_Hist.Fec_Cre, RF_base_Completa_Hist.Fec_Ini_Cup, RF_base_Completa_Hist.Fec_Vcto_Cup, RF_base_Completa_Hist.Fec_Rep, RF_base_Completa_Hist.Fec_Vcto, RF_base_Completa_Hist.Dias_Liq, RF_base_Completa_Hist.Dias_Vcto, RF_base_Completa_Hist.Cap_Amort, RF_base_Completa_Hist.Int_Total_Cont, 0 AS Int_Devengado, RF_base_Completa_Hist.Tasa_Cont, RF_base_Completa_Hist.VP_Cap_Amort, RF_base_Completa_Hist.VP_Int_Total, RF_base_Completa_Hist.Tipo_Cupon, RF_base_Completa_Hist.Cod_Area_Neg, RF_base_Completa_Hist.Cod_Estrategia, RF_base_Completa_Hist.Tipo_Book, RF_base_Completa_Hist.Clasificacion_Contable, RF_base_Completa_Hist.RUT_cli, RF_base_Completa_Hist.Nombre_Cli, RF_base_Completa_Hist.Moneda_Liq, RF_base_Completa_Hist.Dias_Pacto, "" AS Factor_Riesgo, "" AS Codigo_Ejecutivo, "" AS Indexador, "" AS tasa, "" AS tasa_CF, "" AS spread
FROM RF_Fecha_Proceso_Carteras INNER JOIN RF_base_Completa_Hist ON RF_Fecha_Proceso_Carteras.Fecha = RF_base_Completa_Hist.Fec_Pro
WHERE RF_base_Completa_Hist.Cod_Pro <>"Spot"  AND  RF_base_Completa_Hist.Cod_Pro Like "INVERSIONES FINANCIERAS FONDOS MUTUOS";
